const body = $input.first().json.body || $input.first().json;
const project_id = body.project_id;
if (!project_id) throw new Error('project_id required');
const force = body.force === true || body.force === 'true';
return [{ json: { project_id, force } }];

const body = $('Validate').first().json;
const project_id = body.project_id;
const force = body.force === true || body.force === 'true';

const topicsResult = $input.first().json;
const existingTopics = Array.isArray(topicsResult) ? topicsResult : [];
const existingCount = existingTopics.length;

const project = $('Read Project').first().json[0] || {};
const isCrashResume = force && project.status === 'generating_topics';

if (existingCount > 0 && !force) {
  return [{ json: { topics_exist: true, count: existingCount, project_id, __early_return: true } }];
}

let startTopicNumber, topicsNeeded;
if (isCrashResume && existingCount % 25 !== 0) {
  startTopicNumber = existingCount + 1;
  topicsNeeded = 25 - (existingCount % 25);
} else {
  startTopicNumber = existingCount + 1;
  topicsNeeded = 25;
}

const existingTitles = existingTopics.map(t => ({
  topic_number: t.topic_number,
  seo_title: t.seo_title,
  narrative_hook: t.narrative_hook
}));

return [{ json: { project_id, force, isCrashResume, existingCount, startTopicNumber, topicsNeeded, existingTitles, __early_return: false } }];

const project = $('Read Project').first().json[0] || $('Read Project').first().json;
const masterPrompt = $('Read Prompt Config').first().json[0]?.prompt_text || $('Read Prompt Config').first().json?.prompt_text;
const idempotency = $('Idempotency Guard').first().json;
const project_id = idempotency.project_id;
const topicsNeeded = idempotency.topicsNeeded || 25;
const existingTitles = idempotency.existingTitles || [];
const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const hdr = { 'apikey': SRK, 'Authorization': 'Bearer ' + SRK };

const ca = project.competitive_analysis || {};
const analyses = ca.analyses || [];

let analysisPayload = '';
if (analyses.length > 0) {
  analysisPayload = JSON.stringify({
    primary_analysis: analyses[0],
    additional_analyses: analyses.slice(1),
    project_niche: project.niche,
    project_description: project.niche_description
  }, null, 2);
} else {
  try {
    const resp = await fetch(SB + '/rest/v1/niche_profiles?project_id=eq.' + project_id + '&order=created_at.desc&limit=1', { headers: hdr });
    const profiles = await resp.json();
    const profile = profiles?.[0];
    if (profile) {
      analysisPayload = JSON.stringify({
        niche_category: project.niche,
        project_niche: project.niche,
        project_description: project.niche_description || '',
        channel_name: 'New Channel (this project)',
        video_title: 'N/A — generating from niche research',
        views: 0,
        content_quality: { depth_score: 0, missing_topics: [], unique_insights: [], accuracy_concerns: [] },
        blue_ocean_analysis: {
          what_everyone_does: (profile.competitor_analysis?.gaps || []).map(g => typeof g === 'string' ? g : g.topic || ''),
          gaps_and_opportunities: (profile.blue_ocean_opportunities?.unoccupied_angles || profile.blue_ocean_opportunities?.value_curve_gaps || []),
          contrarian_angles: [],
          untapped_audience_segments: []
        },
        comment_insights: {
          sentiment_summary: 'Mixed — audience seeking authoritative content',
          top_questions: (profile.audience_pain_points?.reddit || []).concat(profile.audience_pain_points?.quora || []).slice(0, 10),
          requests: [],
          complaints: (profile.audience_pain_points?.forums || []).slice(0, 5),
          topic_opportunities: []
        },
        ten_x_strategy: {
          suggested_title: '',
          recommended_angle: project.niche_blue_ocean_strategy || '',
          target_duration: 7200,
          key_differentiators: [],
          opening_hook_suggestion: ''
        },
        opportunity_scorecard: { verdict: 'STRONG_GO', composite_score: 8, market_gap: 8, uniqueness_potential: 8, audience_demand: 7, competition_density: 5 },
        weaknesses: ['No existing channel — greenfield opportunity'],
        strengths: [],
        one_line_summary: 'New channel in ' + project.niche + ' niche — no existing content to compete against',
        competitor_channels: profile.competitor_analysis?.channels || [],
        keyword_research: profile.keyword_research || {}
      }, null, 2);
    }
  } catch (e) {}

  if (!analysisPayload) {
    analysisPayload = JSON.stringify({
      niche_category: project.niche,
      project_niche: project.niche,
      project_description: project.niche_description || '',
      opportunity_scorecard: { verdict: 'STRONG_GO', composite_score: 7 },
      ten_x_strategy: { recommended_angle: project.niche_blue_ocean_strategy || '' }
    }, null, 2);
  }
}

// === ENRICH WITH RESEARCH CATEGORIES + RESULTS ===
// These come from the Research page's multi-source scraping (Reddit, YouTube, TikTok, Trends, Quora)
let researchEnrichment = '';
try {
  // Fetch ranked research categories (AI-categorized topic clusters)
  const rcResp = await fetch(SB + '/rest/v1/research_categories?project_id=eq.' + project_id + '&select=category_name,video_title_suggestion,summary,ranking_score,total_engagement,result_count&order=ranking_score.desc&limit=10', { headers: hdr });
  const categories = await rcResp.json();

  // Fetch top research results (high-engagement individual posts/videos)
  const rrResp = await fetch(SB + '/rest/v1/research_results?project_id=eq.' + project_id + '&select=title,source,engagement_score,raw_text&order=engagement_score.desc&limit=20', { headers: hdr });
  const results = await rrResp.json();

  // Fetch derived keywords from research runs
  const runResp = await fetch(SB + '/rest/v1/research_runs?project_id=eq.' + project_id + '&select=derived_keywords,platforms&order=created_at.desc&limit=1', { headers: hdr });
  const runs = await runResp.json();

  const sections = [];

  if (categories && categories.length > 0) {
    const catList = categories.map((c, i) => {
      return (i + 1) + '. ' + (c.category_name || '') + ' (score: ' + (c.ranking_score || 0) + ', engagement: ' + (c.total_engagement || 0) + ')\n'
        + '   Suggested title: ' + (c.video_title_suggestion || 'N/A') + '\n'
        + '   Summary: ' + (c.summary || '').substring(0, 200);
    }).join('\n');
    sections.push('RANKED TOPIC CATEGORIES (from multi-source research — Reddit, YouTube, TikTok, Trends, Quora):\n' + catList);
  }

  if (results && results.length > 0) {
    // Group by source
    const bySource = {};
    results.forEach(r => {
      const src = r.source || 'unknown';
      if (!bySource[src]) bySource[src] = [];
      bySource[src].push('- [' + (r.engagement_score || 0) + ' engagement] ' + (r.title || r.raw_text || '').substring(0, 150));
    });
    const resultList = Object.entries(bySource).map(([src, items]) => src.toUpperCase() + ':\n' + items.slice(0, 5).join('\n')).join('\n\n');
    sections.push('HIGH-ENGAGEMENT AUDIENCE CONTENT (what real people are discussing/watching):\n' + resultList);
  }

  if (runs && runs[0]?.derived_keywords) {
    const kw = Array.isArray(runs[0].derived_keywords) ? runs[0].derived_keywords.join(', ') : String(runs[0].derived_keywords);
    sections.push('AI-DERIVED KEYWORDS: ' + kw.substring(0, 500));
  }

  if (sections.length > 0) {
    researchEnrichment = '\n\n=== ADDITIONAL RESEARCH DATA (from multi-source scraping) ===\n'
      + 'Use this data to identify audience-validated topic opportunities. Topics that align with high-engagement research results will perform better.\n\n'
      + sections.join('\n\n')
      + '\n=== END RESEARCH DATA ===';
    console.log('Research enrichment: ' + categories.length + ' categories, ' + results.length + ' results, ' + (runs?.[0]?.derived_keywords?.length || 0) + ' keywords');
  }
} catch (e) {
  console.warn('Research enrichment failed (non-fatal): ' + e.message);
}

let prompt = masterPrompt || '';
prompt += '\n\n=== RESEARCH ANALYSIS PAYLOAD ===\n' + analysisPayload;
prompt += researchEnrichment;

if (existingTitles.length > 0) {
  prompt += '\n\nEXISTING TOPICS — avoid overlap:\n' + JSON.stringify(existingTitles);
}



// === CHANNEL ANALYSIS INTELLIGENCE INJECTION ===
// Inject all intelligence from Channel Analyzer into the topic generation prompt
const ctx = project.channel_analysis_context;
const topicsToAvoid = project.topics_to_avoid || [];
const recommendedTopics = project.recommended_topics || [];
const recommendedAngle = project.recommended_angle || '';
const titleDna = project.title_dna_patterns;
const revProjections = project.revenue_projections;

if (ctx || topicsToAvoid.length > 0 || recommendedTopics.length > 0) {
  prompt += '\n\n=== COMPETITIVE INTELLIGENCE (from Channel Analyzer) ===\n';

  if (ctx) {
    if (ctx.blue_ocean_gaps && ctx.blue_ocean_gaps.length > 0) {
      prompt += '\nBLUE-OCEAN OPPORTUNITIES (high priority — at least 40% of topics should target these):\n';
      for (const gap of ctx.blue_ocean_gaps) {
        const g = typeof gap === 'string' ? gap : (gap.topic || gap.opportunity || JSON.stringify(gap));
        const angle = gap.suggested_angle ? ' | Angle: ' + gap.suggested_angle : '';
        const demand = gap.estimated_demand ? ' | Demand: ' + gap.estimated_demand : '';
        prompt += '- ' + g + demand + angle + '\n';
      }
    }

    if (ctx.differentiation_strategy) {
      prompt += '\nDIFFERENTIATION STRATEGY: ' + (typeof ctx.differentiation_strategy === 'string' ? ctx.differentiation_strategy : JSON.stringify(ctx.differentiation_strategy)) + '\n';
    }

    if (ctx.content_pillars && ctx.content_pillars.length > 0) {
      prompt += '\nCONTENT PILLARS (organize topics around these): ' + ctx.content_pillars.join(', ') + '\n';
    }

    if (ctx.comment_content_gaps && ctx.comment_content_gaps.length > 0) {
      prompt += '\nAUDIENCE CONTENT GAPS (from viewer comments — strong demand signals):\n';
      for (const gap of ctx.comment_content_gaps) {
        prompt += '- ' + gap + '\n';
      }
    }

    if (ctx.comment_requested_topics && ctx.comment_requested_topics.length > 0) {
      prompt += '\nTOPICS VIEWERS ARE ACTIVELY REQUESTING:\n';
      for (const t of ctx.comment_requested_topics) {
        prompt += '- ' + t + '\n';
      }
    }

    if (ctx.comment_pain_points && ctx.comment_pain_points.length > 0) {
      prompt += '\nAUDIENCE PAIN POINTS (address these in topics):\n';
      for (const p of ctx.comment_pain_points) {
        prompt += '- ' + p + '\n';
      }
    }

    if (ctx.comment_top_questions && ctx.comment_top_questions.length > 0) {
      prompt += '\nTOP AUDIENCE QUESTIONS (each could be a video topic):\n';
      for (const q of ctx.comment_top_questions) {
        prompt += '- ' + q + '\n';
      }
    }

    if (ctx.moat_indicators) {
      prompt += '\nMOAT OPPORTUNITIES (defensible advantages to build):\n' + JSON.stringify(ctx.moat_indicators) + '\n';
    }
  }

  if (topicsToAvoid.length > 0) {
    prompt += '\nTOPICS TO AVOID (saturated — competitors already dominate these):\n';
    for (const t of topicsToAvoid) {
      prompt += '- ' + t + '\n';
    }
    prompt += 'NONE of the 25 generated topics should cover these saturated subjects.\n';
  }

  if (recommendedTopics.length > 0) {
    prompt += '\nRECOMMENDED TOPIC SEEDS (use as starting points, expand creatively):\n';
    for (const t of recommendedTopics) {
      const title = typeof t === 'string' ? t : (t.topic || t.title || JSON.stringify(t));
      const angle = t.angle ? ' | Angle: ' + t.angle : '';
      const formula = t.suggested_title_formula ? ' | Formula: ' + t.suggested_title_formula : '';
      prompt += '- ' + title + angle + formula + '\n';
    }
  }

  if (recommendedAngle) {
    prompt += '\nRECOMMENDED CHANNEL ANGLE: ' + recommendedAngle + '\n';
  }

  if (titleDna) {
    prompt += '\nCOMPETITOR TITLE DNA (use these patterns for CTR optimization):\n' + JSON.stringify(titleDna) + '\n';
  }

  if (revProjections) {
    prompt += '\nREVENUE CONTEXT: ' + JSON.stringify(revProjections) + '\n';
  }
}

// Niche viability + depth + thumbnail + scripting reference
const viabScore = project.niche_viability_score;
const viabVerdict = project.niche_viability_verdict;
if (viabScore || viabVerdict) {
  prompt += '
NICHE VIABILITY: Score ' + (viabScore || 'N/A') + '/100 - ' + (viabVerdict || 'N/A') + '
';
}
const scriptTargets = project.script_depth_targets;
if (scriptTargets) {
  prompt += '
SCRIPT DEPTH TARGETS: ' + JSON.stringify(scriptTargets) + '
';
}
const thumbDna = project.thumbnail_dna_patterns;
if (thumbDna) {
  prompt += '
THUMBNAIL VISUAL DNA: ' + JSON.stringify(thumbDna) + '
';
}
const scriptRef = project.script_reference_data;
if (scriptRef) {
  prompt += '
COMPETITOR SCRIPTING REFERENCE:
' + JSON.stringify(scriptRef) + '
';
}
// === END INTELLIGENCE INJECTION ===

return [{ json: { project_id, niche: project.niche, prompt } }];

const response = $input.first().json;
if (response.error || response.type === 'error') {
  return [{ json: {
    isError: true,
    error_message: response.error?.message || JSON.stringify(response.error || response),
    project_id: $('Validate').first().json.project_id
  }}];
}
if (response.stop_reason === 'max_tokens') {
  return [{ json: {
    isError: true,
    error_message: 'Claude response truncated (stop_reason=max_tokens, output_tokens=' + (response.usage?.output_tokens || 'unknown') + '). Topics JSON incomplete.',
    project_id: $('Validate').first().json.project_id
  }}];
}
return [{ json: { ...response, isError: false } }];

const response = $input.first().json;
if (response.error) throw new Error('Anthropic error: ' + (response.error.message || JSON.stringify(response.error)));

const text = (response.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
let jsonText = text.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
const s = jsonText.indexOf('{'), e = jsonText.lastIndexOf('}');
if (s === -1 || e === -1) throw new Error('No JSON object in response');
const parsed = JSON.parse(jsonText.substring(s, e + 1));

const project_id = $('Validate').first().json.project_id;
const startTopicNumber = $('Idempotency Guard').first().json.startTopicNumber || 1;

const playlists = parsed.playlists || [];
const topicRows = [];
const avatarData = [];
const playlistMeta = [];

let globalTopicNum = startTopicNumber;

for (let pi = 0; pi < playlists.length; pi++) {
  const pl = playlists[pi];
  playlistMeta.push({ name: pl.playlist_title, theme: pl.playlist_theme });

  for (const t of (pl.topics || [])) {
    topicRows.push({
      project_id,
      topic_number: t.topic_number || globalTopicNum,
      playlist_group: pi + 1,
      playlist_angle: pl.playlist_title || '',
      original_title: t.subtopic || '',
      seo_title: t.subtopic || '',
      narrative_hook: t.primary_problem_trigger || '',
      key_segments: t.video_style_structure || '',
      estimated_cpm: null,
      viral_potential: null,
      core_domain_framework: t.core_domain_framework || '',
      primary_problem_trigger: t.primary_problem_trigger || '',
      target_audience_segment: t.target_audience_segment || '',
      psychographics: t.psychographics || '',
      key_emotional_drivers: t.key_emotional_drivers || '',
      video_style_structure: t.video_style_structure || '',
      content_angle_blue_ocean: t.content_angle_blue_ocean || '',
      viewer_search_intent: t.viewer_search_intent || '',
      practical_takeaways: t.practical_takeaways || '',
      review_status: 'pending',
      status: 'pending'
    });

    avatarData.push({
      audience_avatar: t.audience_avatar || '',
      psychographics: t.psychographics || '',
      key_emotional_drivers: t.key_emotional_drivers || '',
      target_audience_segment: t.target_audience_segment || '',
      viewer_search_intent: t.viewer_search_intent || ''
    });

    globalTopicNum++;
  }
}

return [{ json: { project_id, topicRows, avatarData, playlistMeta } }];

// INSERT Topics returns 25 separate items — use $input.all()
const topics = $input.all().map(item => item.json);
const avatarData = $('Parse Topics').first().json.avatarData;
const topicRows = $('Parse Topics').first().json.topicRows;
const project_id = $('Validate').first().json.project_id;
const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const AK = $env.ANTHROPIC_API_KEY;

// Build avatar list text for Claude extraction
const avatarDescs = topics.map((t, i) => {
  const a = avatarData[i] || {};
  const tr = topicRows[i] || {};
  return `Avatar ${i+1}:\n- Name: ${(a.audience_avatar || '').substring(0, 100)}\n- Topic: ${t.seo_title || t.original_title}\n- Audience: ${a.target_audience_segment || ''}\n- Psycho: ${(a.psychographics || '').substring(0, 200)}\n- Pain: ${(tr.primary_problem_trigger || '').substring(0, 150)}`;
}).join('\n\n');

// Call Claude to extract 4 missing fields for all avatars in one batch
const prompt = `For each avatar below, extract/infer these 4 fields (1-2 sentences each):\n1. occupation_income — job/role and income bracket\n2. spending_profile — spending behavior relevant to topic\n3. knowledge_level — beginner/intermediate/advanced + brief note\n4. objection — #1 reason they would NOT act on this video\n\n${avatarDescs}\n\nReturn ONLY valid JSON array:\n[{"avatar_index":1,"occupation_income":"...","spending_profile":"...","knowledge_level":"...","objection":"..."}, ...]\nNo markdown. Valid JSON only.`;

let extracted = [];
try {
  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {'Content-Type': 'application/json', 'x-api-key': AK, 'anthropic-version': '2023-06-01'},
    body: JSON.stringify({model: 'claude-sonnet-4-20250514', max_tokens: 16000, messages: [{role: 'user', content: prompt}]})
  });
  const d = await resp.json();
  const txt = (d.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  const clean = txt.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
  extracted = JSON.parse(clean.substring(clean.indexOf('['), clean.lastIndexOf(']') + 1));
} catch (e) {
  // Non-fatal — avatars will have partial data
}

// Build avatar rows with all fields
const avatarRows = topics.map((t, i) => {
  const a = avatarData[i] || {};
  const tr = topicRows[i] || {};
  const ext = extracted.find(e => e.avatar_index === i + 1) || {};
  const avatarText = a.audience_avatar || '';

  return {
    topic_id: t.id,
    project_id,
    video_title_short: t.seo_title || t.original_title,
    avatar_name_age: avatarText.split('.')[0]?.trim()?.substring(0, 100) || null,
    occupation_income: ext.occupation_income || null,
    life_stage: a.target_audience_segment || null,
    pain_point: tr.primary_problem_trigger || null,
    spending_profile: ext.spending_profile || null,
    knowledge_level: ext.knowledge_level || null,
    emotional_driver: a.key_emotional_drivers || null,
    online_hangouts: (a.viewer_search_intent || '').substring(0, 200) || null,
    objection: ext.objection || null,
    dream_outcome: (tr.practical_takeaways || '').substring(0, 200) || null,
    psychographics: a.psychographics || null,
    key_emotional_drivers: a.key_emotional_drivers || null,
    target_audience_segment: a.target_audience_segment || null,
    viewer_search_intent: a.viewer_search_intent || null,
    review_status: 'pending'
  };
});

// Update playlist metadata on project (non-fatal)
const playlistMeta = $('Parse Topics').first().json.playlistMeta || [];
const patch = {};
for (let i = 0; i < Math.min(playlistMeta.length, 5); i++) {
  patch['playlist' + (i+1) + '_name'] = playlistMeta[i].name || '';
  patch['playlist' + (i+1) + '_theme'] = playlistMeta[i].theme || '';
}
if (Object.keys(patch).length > 0) {
  try {
    await fetch(SB + '/rest/v1/projects?id=eq.' + project_id, {
      method: 'PATCH',
      headers: { 'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(patch)
    });
  } catch (e) { /* non-fatal */ }
}

return [{ json: { project_id, avatarRows, topicsInserted: topics.length } }];

const project = $('Read Project').first().json[0] || $('Read Project').first().json;
const buildPrompt = $('Build Prompt').first().json;

const systemPrompt = 'You are a Senior Content Strategist and Niche Domain Researcher operating as the topic generation engine inside a YouTube content pipeline. Your expertise: blue-ocean market strategy, deep niche authority positioning, YouTube algorithm mechanics, high-converting copywriting, and audience psychographic profiling. Your mandate: consume the research analysis, extract every exploitable signal, and engineer 25 video topics that occupy uncontested market space within the identified niche.';

const body = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 64000,
  system: systemPrompt,
  messages: [{ role: 'user', content: buildPrompt.prompt }]
};

return [{ json: { anthropicBody: JSON.stringify(body) } }];
